mapper.select:
SELECT id
FROM booking_reservation
WHERE status = 'APPLIED'
  AND start_time <= #{deadline}
ORDER BY start_time ASC
LIMIT #{limit}

SELECT COUNT(1)
FROM booking_reservation br
         LEFT JOIN venue v ON v.id = br.venue_id
WHERE br.user_id = #{userId}

    AND v.name LIKE CONCAT('%', #{venueNameLike}, '%')


    AND br.status = #{status}


    AND br.start_time >= #{startTime}


    AND br.start_time < #{endTime}

SELECT br.id, br.user_id, br.venue_id, v.name AS venue_name, br.start_time, br.end_time, br.status, br.cancel_time, br.cancel_reason, br.cancel_remark, br.verify_time, br.violation_time, br.violation_type, br.create_time, br.update_time FROM booking_reservation br LEFT JOIN venue v ON v.id = br.venue_id WHERE br.user_id = #{userId}
AND v.name LIKE CONCAT('%', #{venueNameLike}, '%')
AND br.status = #{status}
AND br.start_time >= #{startTime}
AND br.start_time < #{endTime}
ORDER BY br.start_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM booking_reservation br
         LEFT JOIN venue v ON v.id = br.venue_id
WHERE 1 = 1

    AND v.name LIKE CONCAT('%', #{venueNameLike}, '%')


    AND br.status = #{status}


    AND br.start_time >= #{startTime}


    AND br.start_time < #{endTime}


    AND br.user_id IN (
        SELECT id FROM sys_user WHERE username LIKE CONCAT('%', #{usernameLike}, '%')
    )

SELECT br.id, u.username AS user_name, v.name AS venue_name, br.start_time, br.end_time, br.status, br.cancel_time, br.cancel_reason, br.cancel_remark, br.verify_time, br.violation_time, br.violation_type, br.create_time AS create_time, br.update_time AS update_time FROM booking_reservation br JOIN sys_user u ON u.id = br.user_id LEFT JOIN venue v ON v.id = br.venue_id WHERE 1 = 1
AND v.name LIKE CONCAT('%', #{venueNameLike}, '%')
AND br.status = #{status}
AND br.start_time >= #{startTime}
AND br.start_time < #{endTime}
AND br.user_id IN ( SELECT su.id FROM sys_user su WHERE su.username LIKE CONCAT('%', #{usernameLike}, '%') )
ORDER BY br.start_time DESC LIMIT #{offset}, #{pageSize}
